                let instance_ini_exists = self.mo2_file_exists(
                    &instance_ini_path,
                    steps,
                    ModManagerDiscoveryStage::LocalAppDataInstanceIni,
                )?;
                if instance_ini_exists {
                    let configuration =
                        self.parse_mo2_ini(manager.clone(), &instance_ini_path, None, false)?;
