    let snapshot = OverviewSnapshot::loading("Refreshing Overview...");
    let refresh = WorkerEvent::completed(
        task.clone(),
        WorkerPayload::Overview(OverviewWorkerPayload::refresh_completed(1, snapshot.clone())),
