            refresh_id: 1,
            snapshot: ref actual,
        }) if *actual == snapshot
    ));
    assert!(matches!(
        update.payload,
        WorkerPayload::Overview(OverviewWorkerPayload::UpdateCheckCompleted {
            refresh_id: 1,
            update_banner: UpdateBannerState::Disabled,
        })
    ));
}

